    90	int
    91	choose(int n,
    92	       int k)
    93	//------------------------------------------------------------------------------
    94	{
    95	  int res = 1;
    96	  int res2 = 1;
    97	  int i;
    98	
    99	  if (k > n)
   100	    return (0);
   101	
   102	  if (n == k)
   103	    return (1);
   104	
   105	  for (i = n; i > k; i--)
   106	    res *= i;
   107	
   108	  for (i = 2; i <= (n - k); i++)
   109	    res2 *= i;
   110	
   111	  return (res / res2);
   112	}
