   114	//------------------------------------------------------------------------------
   115	// Patented algorithm from Yang et al, US Patent 2009, "Channel Quality Indexing and Reverse Indexing"
   116	void reverse_index(int N,
   117	                   int M,
   118	                   int r,
   119	                   int *v)
   120	//------------------------------------------------------------------------------
   121	{
   122	  int BaseValue = 0;
   123	  int IncreaseValue, ThresholdValue;
   124	  int sumV;
   125	  int i;
   126	  r = choose(N, M) - 1 - r;
   127	  memset((void *) v, 0, M * sizeof(int));
   128	  sumV = 0;
   129	  i = M;
   130	
   131	  while (i > 0 && r > 0) {
   132	    IncreaseValue = choose(N - M + 1 - sumV - v[i - 1] + i - 2,
   133	                           i - 1);
   134	    ThresholdValue = BaseValue + IncreaseValue;
   135	
   136	    if (r >= ThresholdValue) {
   137	      v[i - 1]++;
   138	      BaseValue = ThresholdValue;
   139	    } else {
   140	      r -= BaseValue;
   141	      sumV += v[--i];
   142	      BaseValue = 0;
   143	    }
   144	  }
   145	}
